import Link from "next/link";
import { AppShell } from "@/components/app-shell";
import { SkillForm } from "@/components/skills/skill-form";
import { getAuthContext } from "@/lib/firebase/auth";
import { skillsRepository } from "@/lib/repositories/skills-repository";

export default async function Page() {
  const auth = await getAuthContext();
  if (!auth?.workspaceId) {
    return <AppShell title="Skills"><p>Sessão não encontrada.</p></AppShell>;
  }

  const items = await skillsRepository.list(auth.workspaceId);

  return (
    <AppShell title="Skills">
      <div className="content-stack space-y-6">
        <section className="app-card"><SkillForm /></section>
        <section className="grid gap-4 sm:grid-cols-3">
          {items.map((item) => (
            <article key={item.id} className="list-card">
              <h2 className="font-semibold">{item.name}</h2>
              <p className="mt-1 text-sm muted">{item.prompt || "Sem prompt."}</p>
              <Link href={`/skills/${item.id}`} className="mt-3 inline-block pill-link">Ver detalhe</Link>
            </article>
          ))}
          {items.length === 0 ? <p className="empty-state">Nenhuma skill cadastrada.</p> : null}
        </section>
      </div>
    </AppShell>
  );
}
